<?php session_start(); require 'includes/header.php'; require_login(); $from=$_GET['from']??date('Y-m-01'); $to=$_GET['to']??date('Y-m-t');
$in=$pdo->prepare('SELECT si.received_date d,i.name item,si.qty,si.ref_no FROM stock_in si JOIN items i ON i.id=si.item_id WHERE si.received_date BETWEEN ? AND ? ORDER BY si.received_date'); $in->execute([$from,$to]);
$out=$pdo->prepare('SELECT so.issue_date d,i.name item,so.qty,so.department,so.issued_to FROM stock_out so JOIN items i ON i.id=so.item_id WHERE so.issue_date BETWEEN ? AND ? ORDER BY so.issue_date'); $out->execute([$from,$to]);
$bal=$pdo->query('SELECT item_code,name,current_stock,min_stock,unit FROM items ORDER BY name')->fetchAll();
?><h1>Reports</h1><div class="card"><form><div class="formgrid"><input type="date" name="from" value="<?=e($from)?>"><input type="date" name="to" value="<?=e($to)?>"><button>Generate</button></div></form><button onclick="printPage()">Print / Save PDF</button></div><div class="card"><h3>Stock In Report</h3><table id="rin"><tr><th>Date</th><th>Item</th><th>Qty</th><th>Reference</th></tr><?php foreach($in as $r): ?><tr><td><?=e($r['d'])?></td><td><?=e($r['item'])?></td><td><?=e($r['qty'])?></td><td><?=e($r['ref_no'])?></td></tr><?php endforeach ?></table></div><div class="card"><h3>Stock Out Report</h3><table id="rout"><tr><th>Date</th><th>Item</th><th>Qty</th><th>Department</th><th>Issued To</th></tr><?php foreach($out as $r): ?><tr><td><?=e($r['d'])?></td><td><?=e($r['item'])?></td><td><?=e($r['qty'])?></td><td><?=e($r['department'])?></td><td><?=e($r['issued_to'])?></td></tr><?php endforeach ?></table></div><div class="card"><h3>Stock Balance</h3><table id="rbal"><tr><th>Code</th><th>Item</th><th>Balance</th><th>Minimum</th><th>Status</th></tr><?php foreach($bal as $r): ?><tr><td><?=e($r['item_code'])?></td><td><?=e($r['name'])?></td><td><?=e($r['current_stock'].' '.$r['unit'])?></td><td><?=e($r['min_stock'])?></td><td class="<?=$r['current_stock']<=$r['min_stock']?'low':'ok'?>"><?=$r['current_stock']<=$r['min_stock']?'LOW':'OK'?></td></tr><?php endforeach ?></table></div><?php require 'includes/footer.php'; ?>
